```python
class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __str__(self):
        if self.is_king:
            return f"{'K' if self.color == 'red' else 'k'}"
        return f"P{' ' if self.color == 'red' else ''}"

class Board:
    def __init__(self):
        self.grid = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        colors = ['red', 'black']
        for row in range(3):
            for col in range(8):
                if (row + col) % 2 == 1:
                    self.grid[row][col] = Piece(colors[(col // 2) % 2])
        for row in range(5, 8):
            for col in range(8):
                if (row + col) % 2 == 1:
                    self.grid[row][col] = Piece(colors[not ((col // 2) % 2)])

    def get_piece(self, row, col):
        return self.grid[row][col]

    def set_piece(self, row, col, piece):
        self.grid[row][col] = piece

    def remove_piece(self, row, col):
        self.grid[row][col] = None

class CheckersGame:
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'

    def make_move(self, from_pos, to_pos):
        from_row, from_col = int(from_pos[0]) - 1, int(from_pos[1]) - 1
        to_row, to_col = int(to_pos[0]) - 1, int(to_pos[1]) - 1

        piece = self.board.get_piece(from_row, from_col)
        if not piece or piece.color != self.current_player:
            raise ValueError("Invalid move: Invalid piece selected")

        # Move the piece
        self.board.remove_piece(from_row, from_col)
        self.board.set_piece(to_row, to_col, piece)

        # Handle promotion
        if (self.current_player == 'red' and to_row == 0) or (self.current_player == 'black' and to_row == 7):
            piece.is_king = True

        # Switch player
        self.current_player = 'black' if self.current_player == 'red' else 'red'

    def is_game_over(self):
        return False  # Placeholder for game over logic

class GameUI:
    @staticmethod
    def print_board(board):
        for row in board.grid:
            print(' '.join(str(piece) for piece in row))

    @staticmethod
    def get_move():
        move = input("Enter move (e.g., A1 B2): ").upper()
        return move

    @staticmethod
    def display_winner(winner):
        print(f"Game Over! {winner.capitalize()} wins!")

def main():
    game = CheckersGame()
    ui = GameUI()

    while not game.is_game_over():
        ui.print_board(game.board)
        move = ui.get_move()
        try:
            game.make_move(move[0:2], move[3:])
        except ValueError as e:
            print(e)

if __name__ == "__main__":
    main()
```

